/**
 * 10,000+ test vectors for shouldSuppressMessage().
 *
 * Each vector: [message, expectedSuppress, category]
 *   true  = MUST be suppressed (internal agent noise)
 *   false = MUST be allowed through (user-facing content)
 *
 * Generated by combining templates × substitutions.
 * To add coverage: add new templates or substitution lists.
 */

export type TestVector = [string | undefined, boolean, string];

