// ─── ALLOW: Product search results ──────────────────────────────────────────
function genUserResults(): TestVector[] {
  const vecs: TestVector[] = [];
  for (const p of PRODUCTS) {
    const price = sPick(PRICES);
    const rating = sPick(RATINGS);
    vecs.push([`${p} — ${price}`, false, 'user-results']);
    vecs.push([`${p} is available for ${price}`, false, 'user-results']);
    vecs.push([`${p} · ${rating} · ${price}`, false, 'user-results']);
    vecs.push([`${p} — ${price}, ${sPick(FEATURES)}`, false, 'user-results']);
  }
  for (const h of HOTELS) {
    const price = sPick(PRICES);
    const rating = sPick(RATINGS);
    vecs.push([`${h} — ${price}/night, ${rating}`, false, 'user-results']);
    vecs.push([`${h} is available for ${price}/night`, false, 'user-results']);
    vecs.push([`${h} — ${price}/night, ${sPick(FEATURES)}`, false, 'user-results']);
  }
  // Aggregate results
  vecs.push(['Here are the top wireless earbuds under ₹2,000 on Flipkart', false, 'user-results']);
  vecs.push(['Here are 5 dal options from Blinkit', false, 'user-results']);
  vecs.push(['Here are 3 hotels in Mumbai under ₹4000/night', false, 'user-results']);
  for (let i = 1; i <= 15; i++) {
    vecs.push([`I found ${i} options matching your search`, false, 'user-results']);
  }
  return vecs;
}

