// ─── ALLOW: Cart-related user messages ──────────────────────────────────────
function genCartMessages(): TestVector[] {
  const vecs: TestVector[] = [];
  for (const p of PRODUCTS) {
    const price = sPick(PRICES);
    vecs.push([`${p} (${price}) added to cart`, false, 'cart']);
    vecs.push([`Removed ${p} from your cart`, false, 'cart']);
    vecs.push([`${p} quantity updated to 2`, false, 'cart']);
    vecs.push([`${p} is no longer available — removed from cart`, false, 'cart']);
  }
  for (let n = 1; n <= 10; n++) {
    const total = sPick(PRICES);
    vecs.push([`Your cart: ${n} item${n > 1 ? 's' : ''}, total ${total}`, false, 'cart']);
    vecs.push([`Cart updated: ${n} item${n > 1 ? 's' : ''} — ${total}`, true, 'cart']);
  }
  vecs.push(['Your cart is empty', false, 'cart']);
  vecs.push(['Cart cleared', false, 'cart']);
  vecs.push(['Minimum order amount not met — add ₹60 more', false, 'cart']);
  return vecs;
}

