// ─── ALLOW: Spec / feature combos for products ─────────────────────────────
function genSpecMessages(): TestVector[] {
  const vecs: TestVector[] = [];
  for (const p of PRODUCTS) {
    for (const f1 of pickN(FEATURES, 3)) {
      for (const f2 of pickN(FEATURES, 2)) {
        if (f1 !== f2) {
          vecs.push([`${p}: ${f1}, ${f2}`, false, 'spec']);
        }
      }
    }
  }
  return vecs;
}

